def _strip_transient_fields(use_case: dict) -> dict:
    """Remove transient/validation fields from a use case dict to reduce memory footprint."""
    for field in _TRANSIENT_UC_FIELDS:
        use_case.pop(field, None)
    return use_case

def _force_gc(logger=None, reason: str = ""):
    """Force garbage collection and log memory stats."""
    gc.collect()
    try:
        import psutil
        proc = psutil.Process(os.getpid())
        mem_mb = proc.memory_info().rss / (1024 * 1024)
        if logger:
            logger.info(f"🧹 GC forced{f' ({reason})' if reason else ''}: RSS={mem_mb:.0f} MB")
    except ImportError:
        if logger:
            logger.debug(f"🧹 GC forced{f' ({reason})' if reason else ''}")


